     3→namespace App\Traits;
     4→
     5→use App\Models\ActivityLog;
     6→
     7→trait LogsActivity
     8→{
     9→    public static function bootLogsActivity(): void
    10→    {
    11→        static::created(function ($model) {
    12→            if (! auth()->check()) {
    13→                return;
    14→            }
    15→
    16→            ActivityLog::create([
    17→                'loggable_type' => get_class($model),
    18→                'loggable_id'   => $model->id,
    19→                'user_id'       => auth()->id(),
    20→                'event'         => 'created',
    21→                'old_values'    => null,
    22→                'new_values'    => $model->getLoggableAttributeValues(),
    23→                'created_at'    => now(),
    24→            ]);
    25→        });
    26→
    27→        static::updating(function ($model) {
    28→            if (! auth()->check()) {
    29→                return;
    30→            }
    31→
    32→            $watchedKeys = $model->loggableAttributes ?? [];
    33→            $changedKeys = array_intersect(array_keys($model->getDirty()), $watchedKeys);
    34→
    35→            if (empty($changedKeys)) {
    36→                return;
    37→            }
    38→
    39→            $oldValues = [];
    40→            $newValues = [];
    41→            foreach ($changedKeys as $key) {
    42→                $oldValues[$key] = $model->getOriginal($key);
    43→                $newValues[$key] = $model->getDirty()[$key];
    44→            }
    45→
    46→            ActivityLog::create([
    47→                'loggable_type' => get_class($model),
    48→                'loggable_id'   => $model->id,
    49→                'user_id'       => auth()->id(),
    50→                'event'         => 'updated',
    51→                'old_values'    => $oldValues,
    52→                'new_values'    => $newValues,
    53→                'created_at'    => now(),
    54→            ]);
    55→        });
    56→
    57→        static::deleting(function ($model) {
    58→            if (! auth()->check()) {
    59→                return;
    60→            }
    61→
    62→            ActivityLog::create([
    63→                'loggable_type' => get_class($model),
    64→                'loggable_id'   => $model->id,
    65→                'user_id'       => auth()->id(),
    66→                'event'         => 'deleted',
    67→                'old_values'    => $model->getLoggableAttributeValues(),
    68→                'new_values'    => null,
    69→                'created_at'    => now(),
    70→            ]);
    71→        });
    72→    }
    73→
    74→    protected function getLoggableAttributeValues(): array
    75→    {
    76→        $watchedKeys = $this->loggableAttributes ?? [];
    77→        return collect($this->getAttributes())->only($watchedKeys)->toArray();
    78→    }
    79→}
